mapper.select:
select member_id as "member_id", email as "email", password as "password", name as "name", nickname as "nickname" , profile_image as "profile_image" , social_type as "social_type", role as "role", access_token as "access_token" , refresh_token as "refresh_token", create_date as "create_date" , latest_date as "latest_date", status as "status" from member
and upper(trim(status)) = upper(trim(#{status}))
and role = #{role}
and create_date >= #{joinDateStart}
and create_date <= #{joinDateEnd}
and latest_date is not null and to_char(latest_date, 'YYYY-MM-DD') >= #{lastLoginStart}
and latest_date is not null and to_char(latest_date, 'YYYY-MM-DD') <= #{lastLoginEnd}
and upper(trim(social_type)) = upper(trim(#{socialType}))
and lower(email) like '%' || lower(#{keyword}) || '%'
and lower(name) like '%' || lower(#{keyword}) || '%'
and lower(nickname) like '%' || lower(#{keyword}) || '%'
order by create_date desc nulls last

